import React, {
  useState,
  useEffect,
  useContext,
  useMemo,
  useRef,
  useCallback,
} from 'react';
import { useSpring } from '@react-spring/web';
import { useGesture } from '@use-gesture/react';
import { useMediaQuery } from 'react-responsive';

export type Lang = 'fr' | 'en';

/** Angle de repos du bloc titre (rotateX) pour une langue donnée. */
export function restDeg(lang: Lang, dir: number): number {
  if (lang === 'fr') return 0;
  return dir * 720;
}

export interface LangContextValue {
  lang: Lang;
  setLang: React.Dispatch<React.SetStateAction<Lang>>;
  setLangAnimating: React.Dispatch<React.SetStateAction<boolean>>;
  langAnimating: boolean;
  langAnimatingRef: React.MutableRefObject<boolean>;
  flipGeneration: number;
}

export const LangCtxt = React.createContext<LangContextValue | null>(null);

/** Cumul molette (px) pour déclencher un flip. */
const WHEEL_FLIP_ACCUM = 72;
const DRAG_TOGGLE_AT_DESKTOP = 250;
const DRAG_TOGGLE_AT_MOBILE = 120;
const AXIS_RATIO = 1.15;

/** Phase 1 : premier 720° — plutôt vif. */
const phase1 = { tension: 260, friction: 24 };
/** Phase 2 : second 720° — encore un peu d’énergie. */
const phase2 = { tension: 160, friction: 30 };
/** Phase 3 : atterrissage sur la position de repos — amorti. */
const phase3 = { tension: 68, friction: 44 };

export function useCreateToggleScroll(
  setToggleContact: React.Dispatch<React.SetStateAction<boolean>>,
  toggleContact: boolean,
  setToggleExps: React.Dispatch<React.SetStateAction<boolean>>,
  toggleExps: boolean
) {
  const isNarrow = useMediaQuery({ maxWidth: 750 });
  const dragToggleAt = isNarrow ? DRAG_TOGGLE_AT_MOBILE : DRAG_TOGGLE_AT_DESKTOP;

  const [lang, setLang] = useState<Lang>('fr');
  const [langAnimating, setLangAnimating] = useState(false);
  const langAnimatingRef = useRef(false);
  const [flipGeneration, setFlipGeneration] = useState(0);

  const wheelAcc = useRef(0);
  const wheelIdleTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const requestLangFlip = useCallback(() => {
    if (langAnimatingRef.current) return;
    langAnimatingRef.current = true;
    setLangAnimating(true);
    setFlipGeneration(g => g + 1);
  }, []);

  const handleMenu = useCallback(
    (limit: number, deltaX: number, direction: number) => {
      if (Math.abs(deltaX) <= limit) return;
      if (direction < 0) {
        if (!toggleContact && !toggleExps) {
          setToggleContact(true);
        } else if (!toggleContact && toggleExps) {
          setToggleExps(false);
        }
      } else if (direction > 0) {
        if (!toggleContact && !toggleExps) {
          setToggleExps(true);
        } else if (toggleContact && !toggleExps) {
          setToggleContact(false);
        }
      }
    },
    [setToggleContact, setToggleExps, toggleContact, toggleExps]
  );

  const handleGestureWheel = useCallback(
    (e: { delta: [number, number]; axis: 'x' | 'y' | undefined }) => {
      if (langAnimatingRef.current) return;
      const { delta, axis } = e;
      if (axis === 'x') return;

      wheelAcc.current += delta[1];
      if (Math.abs(wheelAcc.current) >= WHEEL_FLIP_ACCUM) {
        requestLangFlip();
        wheelAcc.current = 0;
      }

      if (wheelIdleTimer.current) clearTimeout(wheelIdleTimer.current);
      wheelIdleTimer.current = setTimeout(() => {
        wheelAcc.current = 0;
        wheelIdleTimer.current = null;
      }, 280);
    },
    [requestLangFlip]
  );

  const handleGestureDrag = useCallback(
    (e: {
      event?: UIEvent;
      movement: [number, number];
      direction: [number, number];
      last: boolean;
    }) => {
      if (langAnimatingRef.current) return;

      if (e.event && 'preventDefault' in e.event) {
        e.event.preventDefault();
      }

      const { movement, direction, last } = e;
      const absX = Math.abs(movement[0]);
      const absY = Math.abs(movement[1]);

      const verticalDominant = absY > absX * AXIS_RATIO;
      const horizontalDominant = absX > absY * AXIS_RATIO;

      if (!last) return;

      if (verticalDominant) {
        if (absY >= dragToggleAt) {
          requestLangFlip();
        }
        return;
      }

      if (horizontalDominant) {
        handleMenu(140, absX, direction[0]);
      }
    },
    [handleMenu, dragToggleAt, requestLangFlip]
  );

  useEffect(() => {
    return () => {
      if (wheelIdleTimer.current) clearTimeout(wheelIdleTimer.current);
    };
  }, []);

  const bindGesture = useGesture(
    {
      onDrag: state => handleGestureDrag(state),
      onWheel: state => handleGestureWheel(state),
    },
    {
      drag: {
        filterTaps: true,
        threshold: 18,
        rubberband: false,
      },
      wheel: {
        eventOptions: { passive: false },
      },
    }
  );

  const valuesLangCtxt = useMemo(
    () => ({
      lang,
      setLang,
      setLangAnimating,
      langAnimating,
      langAnimatingRef,
      flipGeneration,
    }),
    [lang, langAnimating, flipGeneration]
  );

  return {
    valuesLangCtxt,
    ToggleProvider: LangCtxt.Provider,
    bindGesture,
  };
}

export function useToggleScroll(dir: number = 1) {
  const ctx = useContext(LangCtxt);
  if (!ctx) {
    throw new Error('useToggleScroll must be used within LangCtxt provider');
  }
  const { lang, setLang, langAnimating, langAnimatingRef, flipGeneration } =
    ctx;

  const [styles, api] = useSpring(() => ({
    transform: `rotateX(${restDeg(lang, dir)}deg)`,
  }));

  useEffect(() => {
    if (langAnimating) return;
    api.set({ transform: `rotateX(${restDeg(lang, dir)}deg)` });
  }, [lang, langAnimating, dir, api]);

  useEffect(() => {
    if (flipGeneration === 0) return;

    const fromLang = lang;
    const toLang: Lang = fromLang === 'fr' ? 'en' : 'fr';
    const fromDeg = restDeg(fromLang, dir);
    const toDeg = restDeg(toLang, dir);
    const a1 = fromDeg + dir * 720;
    const a2 = fromDeg + dir * 1440;

    api.start({
      from: { transform: `rotateX(${fromDeg}deg)` },
      to: [
        { transform: `rotateX(${a1}deg)`, config: phase1 },
        { transform: `rotateX(${a2}deg)`, config: phase2 },
        { transform: `rotateX(${toDeg}deg)`, config: phase3 },
      ],
      onRest: () => {
        setLang(toLang);
        langAnimatingRef.current = false;
        setLangAnimating(false);
      },
    });
  }, [flipGeneration, dir, api, lang, setLang, langAnimatingRef]);

  return [styles, lang] as const;
}
